using System;

namespace CircleArea
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter the radius of the circle: ");

            // 1. بنقرأ الرقم ونحوله لـ double (عشان نصف القطر ممكن يكون فيه كسور زي 2.5)
            double radius = double.Parse(Console.ReadLine());

            // 2. قاعدة المساحة هي: ط * نق * نق (أو Pi * r * r)
            // استخدمنا Math.PI عشان نجيب قيمة (ط) الدقيقة اللي هي تقريباً 3.14
            double area = Math.PI * radius * radius;

            // 3. بنطبع النتيجة للمستخدم
            Console.WriteLine("Area: " + area);
        }
    }
}

