namespace RightTriangle
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.WriteLine("--- Star Triangle ---");

            // 1. الحلقة الخارجية: بتتحكم في عدد الصفوف (عايزين 5 صفوف)
            for (int row = 1; row <= 5; row++)
            {
                // 2. الحلقة الداخلية (التريكة هنا): 
                // مش هنثبتها تقف عند 5، إحنا هنخليها تقف عند رقم الصف الحالي (row)
                // يعني لو إحنا في الصف الأول، هتلف لفة وتطبع نجمة. 
                // لو في الصف التاني، هتلف لفتين وتطبع نجمتين، وهكذا.
                for (int col = 1; col <= row; col++)
                {
                    Console.Write("* ");
                }

                // 3. ننزل سطر جديد بعد ما نخلص نجوم الصف الحالي
                Console.WriteLine();
            }
        }
    }
}

using System;

namespace SumOfNumbers
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter a number: ");
            int number = int.Parse(Console.ReadLine());

            // 1. بنعمل "حصالة" عشان نجمع فيها الأرقام
            // بدأناها بصفر لأن الصفر هو المحايد الجمعي (مش هيأثر في الجمع)
            int sum = 0;

            // 2. حلقة بتبدأ من 1 وتقف عند الرقم اللي المستخدم دخله
            for (int i = 1; i <= number; i++)
            {
                // 3. في كل لفة، بناخد قيمة العداد (i) ونحطها جوه الحصالة
                sum = sum + i;
            }

            // 4. بعد ما الحلقة تخلص خالص، بنطبع الحصالة فيها كام
            Console.WriteLine("The sum from 1 to " + number + " is: " + sum);
        }
    }
}

using System;

namespace SimpleCalculator
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter first number: ");
            int num1 = int.Parse(Console.ReadLine());

            Console.Write("Enter second number: ");
            int num2 = int.Parse(Console.ReadLine());

            Console.WriteLine("Choose an operation (+, -, *, /): ");
            // بنقرأ العلامة اللي المستخدم دخلها كنص (string)
            string operation = Console.ReadLine();

            // بنستخدم switch عشان نختبر العلامة اللي دخلت وننفذ كود معين على أساسها
            switch (operation)
            {
                case "+":
                    Console.WriteLine("Result = " + (num1 + num2));
                    break; // لازم نكتب break عشان البرنامج يخرج من الـ switch وميكملش باقي الحالات
                case "-":
                    Console.WriteLine("Result = " + (num1 - num2));
                    break;
                case "*":
                    Console.WriteLine("Result = " + (num1 * num2));
                    break;
                case "/":
                    // ضفنا شرط if عشان نمنع القسمة على صفر (تفكير برمجي سليم)
                    if (num2 == 0)
                        Console.WriteLine("Error: Cannot divide by zero!");
                    else
                        Console.WriteLine("Result = " + (num1 / num2));
                    break;
                default:
                    // لو المستخدم دخل علامة غريبة مش في الاختيارات
                    Console.WriteLine("Invalid operation!");
                    break;
            }
        }
    }
}

using System;

namespace PrimeChecker
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter a number: ");
            int number = int.Parse(Console.ReadLine());

            // 1. بنعمل متغير نوعه (صح/غلط) كأنه "علم" أو مؤشر. 
            // هنفترض في الأول إن الرقم "أولي" لحد ما نثبت العكس.
            bool isPrime = true;

            // الأرقام اللي أقل من 2 مش أرقام أولية أساساً
            if (number < 2)
            {
                isPrime = false;
            }
            else
            {
                // 2. بنعمل حلقة تبدأ من 2 لحد الرقم اللي قبل الرقم بتاعنا
                // ليه؟ لأننا عايزين نتأكد إنه مبيقبلش القسمة على أي رقم في النص
                for (int i = 2; i < number; i++)
                {
                    // لو الرقم قِبل القسمة على أي عداد في النص (يعني الباقي صفر)
                    if (number % i == 0)
                    {
                        isPrime = false; // يبقى الرقم ده مش أولي!
                        break; // بنوقف الحلقة فوراً لأننا مش محتاجين نكمل تدوير
                    }
                }
            }

            // 3. في النهاية بنطبع النتيجة بناءً على حالة الـ "علم"
            if (isPrime == true)
                Console.WriteLine(number + " is a Prime number.");
            else
                Console.WriteLine(number + " is NOT a Prime number.");
        }
    }
}

