namespace SentinelLoop
{
    class Program
    {
        static void Main(string[] args)
        {
            int sum = 0;
            int number = 0;

            // حلقة while بتفضل شغالة طول ما الشرط ده بيتحقق (الرقم مش سالب)
            while (number >= 0)
            {
                Console.Write("Enter a positive number (or a negative number to stop): ");
                number = int.Parse(Console.ReadLine());

                // بنتأكد إن الرقم لسه موجب قبل ما نجمعه على الحصالة
                if (number >= 0)
                {
                    sum = sum + number;
                }
            }

            // السطر ده مش هيتنفذ إلا لما المستخدم يدخل رقم سالب والحلقة تكسر
            Console.WriteLine("The total sum of positive numbers is: " + sum);
        }
    }
}

