namespace Checkerboard
{
    class Program
    {
        static void Main(string[] args)
        {
            int n = 5;

            // حلقة الصفوف
            for (int row = 1; row <= n; row++)
            {
                // حلقة الأعمدة
                for (int col = 1; col <= n; col++)
                {
                    // اللوجيك: لو جمعنا رقم الصف على رقم العمود
                    // وطلع الناتج زوجي، بنطبع نجمة. لو فردي، بنطبع مسافة.
                    // ده بيخلق شكل التبادل بتاع رقعة الشطرنج بالظبط!
                    if ((row + col) % 2 == 0)
                    {
                        Console.Write("*");
                    }
                    else
                    {
                        Console.Write(" ");
                    }
                }
                Console.WriteLine();
            }
        }
    }
}

using System;

namespace SumOfDigits
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter a number: ");
            int number = int.Parse(Console.ReadLine());

            int sum = 0;

            // هنفضل شغالين طول ما الرقم لسه فيه خانات
            while (number > 0)
            {
                // بنمسك آخر خانة (باقي القسمة على 10)
                int digit = number % 10;

                // بنجمعها جوه حصالة المجموع
                sum = sum + digit;

                // بنطير الخانة اللي جمعناها عشان اللفة الجاية نجيب اللي بعدها
                number = number / 10;
            }

            Console.WriteLine("Sum of the digits = " + sum);
        }
    }
}

/*
السؤال: ما هو ناتج الكود التالي؟
A) 10
B) 6   <--- الإجابة الصحيحة
C) 4
D) 15

التعليق والشرح:
حلقة الـ for هنا مش بتزيد بمقدار 1، دي بتزيد بمقدار 2 (i += 2).
اللفة الأولى: i = 0 ⬅️ x بقت بـ 0.
اللفة التانية: i = 2 ⬅️ x بقت بـ 2.
اللفة التالتة: i = 4 ⬅️ x بقت (2 + 4) = 6.
اللفة اللي بعدها i هتبقى بـ 6، فالشرط (i < 5) مش هيتحقق والحلقة هتقف، وتطبع 6.
*/

using System;

namespace GuessOutput
{
    class Program
    {
        static void Main(string[] args)
        {
            int x = 0;
            for (int i = 0; i < 5; i += 2)
            {
                x = x + i;
            }
            Console.WriteLine(x);
        }
    }
}

using System;

namespace FactorialCalculator
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter a number: ");
            int number = int.Parse(Console.ReadLine());

            // بنبدأ حصالة الضرب بـ 1 لأن 1 هو المحايد الضربي (عكس الصفر في الجمع)
            // استخدمنا long بدل int عشان المضروب بيكبر بسرعة جداً لو الرقم كبير
            long factorial = 1;

            // الحلقة بتلف من 1 لحد الرقم اللي المستخدم دخله وتضرب الأرقام في بعض
            for (int i = 1; i <= number; i++)
            {
                factorial = factorial * i;
            }

            Console.WriteLine("Factorial of " + number + " is: " + factorial);
        }
    }
}

using System;

namespace MultiplicationTable
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.WriteLine("=== Multiplication Table (1 to 10) ===\n");

            // 1. الحلقة الخارجية للتحكم في الجدول نفسه (من جدول 1 لحد جدول 10)
            for (int i = 1; i <= 10; i++)
            {
                // بنطبع فاصل عشان شكل الخرج يكون نضيف ومرتب
                Console.WriteLine("--- Table of " + i + " ---");

                // 2. الحلقة الداخلية للضرب (بتضرب الرقم اللي بره من 1 لحد 10)
                for (int j = 1; j <= 10; j++)
                {
                    // 3. بنعمل عملية الضرب 
                    int result = i * j;

                    // 4. بنطبع العملية بشكل منسق (3 x 2 = 6)
                    Console.WriteLine(i + " x " + j + " = " + result);
                }

                // بنسيب سطر فاضي بعد كل جدول عشان الشكل
                Console.WriteLine();
            }
        }
    }
}

using System;

namespace CalculatePower
{
    class Program
    {
        static void Main(string[] args)
        {
            // 1. بنطلب من المستخدم يدخل الرقم الأساسي (مثلاً 2)
            Console.Write("Enter the base number: ");
            int baseNum = int.Parse(Console.ReadLine());

            // 2. بنطلب منه يدخل الأُس (مثلاً 3، يعني عايزين نضرب الـ 2 في نفسها 3 مرات)
            Console.Write("Enter the power (exponent): ");
            int power = int.Parse(Console.ReadLine());

            // 3. بنعمل "خزنة" للضرب، وبنبدأها بـ 1 (المحايد الضربي)
            int result = 1;

            // 4. بنعمل حلقة بتلف عدد مرات يساوي الـ (power)
            for (int i = 1; i <= power; i++)
            {
                // 5. في كل لفة، بنضرب النتيجة القديمة في الرقم الأساسي
                result = result * baseNum;
            }

            // 6. بنطبع النتيجة النهائية
            Console.WriteLine(baseNum + " to the power of " + power + " = " + result);
        }
    }
}

