        {
            Console.WriteLine("--- Inverted Star Pyramid ---");

            // 1. الحلقة الخارجية للتحكم في الصفوف
            // بس المرة دي هنبدأ من 5 وننزل لحد 1 (i--)
            for (int row = 5; row >= 1; row--)
