                // في اللفة التانية الـ row هيبقى 4، فهتطبع 4 نجوم.. وهكذا.
                for (int col = 1; col <= row; col++)
                {
                    Console.Write("* ");
                }

                // 3. النزول لسطر جديد بعد نهاية كل صف
                Console.WriteLine();
            }
        }
    }
}

using System;

namespace ReverseNumberMath
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter a number: ");
            int number = int.Parse(Console.ReadLine());

            // المتغير ده هنحوش فيه الرقم المعكوس
            int reversed = 0;

            // الحلقة هتفضل شغالة طول ما الرقم لسه فيه خانات (أكبر من الصفر)
            while (number > 0)
            {
                // 1. بنجيب آخر خانة في الرقم عن طريق باقي القسمة على 10
                // (يعني لو الرقم 1234، باقي قسمته على 10 هو 4)
                int lastDigit = number % 10;

                // 2. بنزق الرقم المعكوس القديم خانة للشمال (نضربه في 10) 
                // ونجمع عليه الخانة الجديدة اللي لسه جايبينها
                reversed = (reversed * 10) + lastDigit;

                // 3. بنطير آخر خانة من الرقم الأصلي عشان اللفة الجاية
                // (القسمة على 10 في الأرقام الصحيحة int بتطير الكسور، يعني 1234 هتبقى 123)
                number = number / 10;
            }

            Console.WriteLine("Reversed Number: " + reversed);
        }
    }
}

using System;

namespace GCD
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter first number: ");
            int a = int.Parse(Console.ReadLine());

            Console.Write("Enter second number: ");
            int b = int.Parse(Console.ReadLine());

            // الفكرة ببساطة (طريقة التبديل وباقي القسمة):
            // بنفضل نجيب باقي قسمة الرقمين على بعض، ونبدلهم، لحد ما واحد فيهم يوصل لصفر.
            while (b != 0)
            {
                // بنحفظ قيمة b القديمة في متغير مؤقت عشان متضيعش
                int temp = b;

                // الـ b الجديدة بتاخد باقي قسمة الرقمين
                b = a % b;

                // الـ a الجديدة بتاخد قيمة الـ b القديمة
                a = temp;
            }

            // لما الحلقة تقف (يعني b بقت بصفر)، القاسم المشترك بيكون متخزن في a
            Console.WriteLine("The Greatest Common Divisor (GCD) is: " + a);
        }
    }
}
